package be.schaubroeck.lpb.rkm.rekenmotor.util;

import be.schaubroeck.lpb.rkm.artikelmotor.ProtoRegul;
import be.schaubroeck.lpb.rkm.rekenmotor.ProtoControle;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.exception.EndingRegulException;
import be.schaubroeck.lpb.rkm.rekenmotor.exception.RegulException;
import be.schaubroeck.lpb.tools.ArtikelAgenda;
import be.schaubroeck.lpb.tools.ControleAgenda;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.RegulAgenda;
import be.schaubroeck.lpb.tools.enumtypes.ArtikelRegulStatus;
import be.schaubroeck.lpb.tools.enumtypes.BronAgenda;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import be.schaubroeck.lpb.tools.enumtypes.RekenControleCode;
import be.schaubroeck.lpb.tools.jpa.al.WerkgeverPO;
import be.schaubroeck.lpb.tools.jpa.lo.ArtikelAgendaPO;
import be.schaubroeck.lpb.tools.jpa.lo.RegulAgendaPK;
import be.schaubroeck.lpb.tools.jpa.lo.RegulAgendaPO;
import be.schaubroeck.lpb.tools.util.LocalDateUtils;
import lombok.extern.slf4j.Slf4j;
import org.joda.time.LocalDate;

import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Set;

@Slf4j
public class RegulManagerImp implements RegulManager {

    private List<RegulAgenda> regulAgenda = new ArrayList<>();
    private List<ArtikelAgenda> artikelAgenda = new ArrayList<>();
    private Set<ProtoRegul> protoReguls = new HashSet<>();
    private Set<ProtoControle> protoWaarschuwing = new HashSet<>();
    private boolean ignoreExceptions = false;

    private List<ControleAgenda> controleAgenda = new ArrayList<>();

    private RegulAgenda maakRegulAgenda(LocalDate beginDatum, Persoon persoon, Integer opdrachtNr, Integer werkgeverId, Regulkode regulKode, String opmerking) {
        RegulAgenda regul = new RegulAgendaPO();
        RegulAgendaPK id = new RegulAgendaPK();
        regul.setId(id);
        regul.setBeginDatum(beginDatum.dayOfMonth().withMinimumValue());
        regul.setEindDatum(beginDatum.dayOfMonth().withMaximumValue());
        regul.setWerkgever(new WerkgeverPO(werkgeverId));
        regul.setPersoon(persoon);
        regul.setOpdrachtNummer(opdrachtNr);
        regul.setRegulStatus(regulKode.getCode());
        regul.setBron(BronAgenda.REKENMOTOR);
        regul.setOpmerking(opmerking != null ? opmerking.replace("€", "Euro") : "");
        return regul;
    }

    private ArtikelAgenda maakArtikelAgenda(
            LocalDate beginDatum, LocalDate boekDatum, Persoon persoon, Integer opdrachtNr, Integer werkgeverId,
            ArtikelRegulStatus regulKode) {
        ArtikelAgenda regul = new ArtikelAgendaPO();
        regul.setBeginDatum(beginDatum.dayOfMonth().withMinimumValue());
        regul.setEindDatum(beginDatum.dayOfMonth().withMaximumValue());
        regul.setStartBoekDatum(boekDatum);
        regul.setStopBoekDatum(boekDatum);
        regul.setWerkgever(new WerkgeverPO(werkgeverId));
        regul.setPersoon(persoon);
        regul.setOpdrachtNummer(opdrachtNr);
        regul.setStatus(regulKode);
        regul.setBron(BronAgenda.REKENMOTOR);
        return regul;
    }

    @Override
    public List<RegulAgenda> getRegulAgenda() {
        return regulAgenda;
    }

    @Override
    public List<ArtikelAgenda> getArtikelAgenda() {
        return artikelAgenda;
    }

    @Override
    public void handleRegulException(RekenTijd rekenTijd, Persoon regulPersoon, RegulException regulException) {
        protoReguls.add(new ProtoRegul(regulException.getBeginDatum(), rekenTijd.boekDatum, regulException.getOpdracht(), regulException.getRegulKode(),
                regulException.getArtikelRegulKode(), regulException.getOpmerking()));
    }

    @Override
    public void addRegul(LocalDate beginDatum, Opdracht opdracht, Regulkode regulKode) {
        protoReguls.add(new ProtoRegul(beginDatum, null, opdracht, regulKode, null, null));
    }

    @Override
    public void addRegul(LocalDate beginDatum, Integer werkgeverId, Integer opdrachtId, Integer opdrachtNr, Regulkode regulKode) {
        protoReguls.add(new ProtoRegul(beginDatum, null, werkgeverId, opdrachtId, opdrachtNr, regulKode, null, null));
    }

    @Override
    public void addArtikelRegul(LocalDate beginDatum, LocalDate boekDatum, Opdracht opdracht, ArtikelRegulStatus regulKode) {
        protoReguls.add(new ProtoRegul(beginDatum, boekDatum, opdracht, null, regulKode, null));
    }

    @Override
    public void doRegulException() {
        if (!ignoreExceptions) {
            throw new EndingRegulException();
        }
    }

    @Override
    public void doRegulException(Opdracht opdracht, Regulkode regulKode) {
        doProtoException(null, null, opdracht, regulKode, null, null);
    }

    @Override
    public void doRegulException(Opdracht opdracht, Regulkode regulKode, String opmerking) {
        doProtoException(null, null, opdracht, regulKode, null, opmerking);
    }

    @Override
    public void doArtikelRegulException(LocalDate boekDatum, Opdracht opdracht, ArtikelRegulStatus regulKode) {
        doProtoException(null, boekDatum, opdracht, null, regulKode, null);
    }

    private void doProtoException(
            LocalDate beginDatum, LocalDate boekDatum, Opdracht opdracht, Regulkode regulKode,
            ArtikelRegulStatus artikelRegulStatus, String opmerking) {
        if (ignoreExceptions) {
            protoReguls.add(new ProtoRegul(beginDatum, boekDatum, opdracht, regulKode, artikelRegulStatus, opmerking));
        } else {
            throw new RegulException(null, opdracht, regulKode, artikelRegulStatus, opmerking);
        }
    }

    @Override
    public boolean hasReguls() {
        return !protoReguls.isEmpty();
    }

    @Override
    public void handleReguls(RekenTijd rekenTijd, Persoon regulPersoon) {
        for (ProtoRegul agenda : protoReguls) {
            LocalDate beginDatum = agenda.getBeginDatum() == null ? rekenTijd.beginDatum : agenda.getBeginDatum().dayOfMonth().withMinimumValue();
            ProtoRegul bepaald = bepaalOpdracht(agenda, regulPersoon);
            if (bepaald == null) {
                for (Opdracht opdracht : regulPersoon.getOpdrachten()) {
                    if (!beginDatum.isAfter(opdracht.getEindDatum())) {
                        bepaald = new ProtoRegul(agenda.getBeginDatum(), agenda.getBoekDatum(), opdracht, agenda.getRegulKode(),
                                agenda.getArtikelRegulStatus(), agenda.getOpmerking());
                        handleRegul(beginDatum, regulPersoon, bepaald);
                    }
                }
            } else {
                handleRegul(beginDatum, regulPersoon, bepaald);
                for (Opdracht opdracht : regulPersoon.getOpdrachten()) {
                    if (!opdracht.getId().equals(agenda.getOpdrachtId()) && !beginDatum.isAfter(opdracht.getEindDatum()) &&
                            !beginDatum.isBefore((opdracht.getBeginDatum()))) {
                        Regulkode nevenRegulKode = bepaald.getRegulKode() != null ? Regulkode.FOUT_ANDERE_OPDRACHT : null;
                        ArtikelRegulStatus nevenArtikelRegulKode =
                                bepaald.getArtikelRegulStatus() != null ? ArtikelRegulStatus.FOUT_ANDERE_OPDRACHT : null;
                        ProtoRegul nevenRegul =
                                new ProtoRegul(agenda.getBeginDatum(), agenda.getBoekDatum(), opdracht, nevenRegulKode, nevenArtikelRegulKode, agenda.getOpmerking());
                        handleRegul(beginDatum, regulPersoon, nevenRegul);
                    }
                }
            }
        }
    }

    private ProtoRegul bepaalOpdracht(ProtoRegul agenda, Persoon regulPersoon) {
        ProtoRegul bepaald = agenda;
        if (!agenda.isOpdrachtBepaald()) {
            Opdracht opdracht = regulPersoon.getOpdrachten().stream().filter(x -> x.getId().equals(agenda.getOpdrachtId())).findFirst().orElse(null);
            if (opdracht != null) {
                bepaald = new ProtoRegul(agenda.getBeginDatum(), agenda.getBoekDatum(), opdracht, agenda.getRegulKode(), agenda.getArtikelRegulStatus(),
                        agenda.getOpmerking());
            } else {
                bepaald = null;
            }
        }
        return bepaald;
    }

    private void handleRegul(LocalDate beginDatum, Persoon persoon, ProtoRegul agenda) {
        if (agenda.getArtikelRegulStatus() != null) {
            doLogRegulagenda(beginDatum, persoon.getId(), agenda.getOpdrachtId(), agenda.getArtikelRegulStatus());
            artikelAgenda.add(maakArtikelAgenda(beginDatum, agenda.getBoekDatum(), persoon, agenda.getOpdrachtNr(), agenda.getWerkgeverId(),
                    agenda.getArtikelRegulStatus()));
        } else {
            Regulkode regulKode = agenda.getRegulKode() == null ? Regulkode.ONBEKENDE_REGUL : agenda.getRegulKode();
            doLogRegulagenda(beginDatum, persoon.getId(), agenda.getOpdrachtId(), regulKode);
            regulAgenda.add(maakRegulAgenda(beginDatum, persoon, agenda.getOpdrachtNr(), agenda.getWerkgeverId(), regulKode, agenda.getOpmerking()));
        }
    }

    @Override
    public void setIgnore(boolean ignore) {
        ignoreExceptions = ignore;
    }

    @Override
    public boolean hasIgnore() {
        return ignoreExceptions;
    }

    private void doLogRegulagenda(LocalDate beginDatum, Integer persoonId, Integer opdrachtId, ArtikelRegulStatus regulKode) {
        log.debug("pid-opdrachtid {}-{} ArtikelRegulStatus:{} Datum:{}", persoonId, opdrachtId, regulKode, LocalDateUtils
                .toNormalString(beginDatum));
    }

    private void doLogRegulagenda(LocalDate beginDatum, Integer persoonId, Integer opdrachtId, Regulkode regulKode) {
        log.debug("pid-opdrachtid {}-{} RegulKode:{} Datum:{}", persoonId, opdrachtId, regulKode, LocalDateUtils.toNormalString(beginDatum));
    }

    @Override
    public void addProtoWaarschuwing(Opdracht opdracht, RekenControleCode controleCode, String omschrijving) {
        protoWaarschuwing.add(new ProtoControle(opdracht, controleCode, omschrijving));
    }

    @Override
    public Set<ProtoControle> getProtoWaarschuwingen() {
        return protoWaarschuwing;
    }

    @Override
    public List<ControleAgenda> getWaarschuwingen() {
        return controleAgenda;
    }


    @Override
    public void addWaarschuwing(ControleAgenda punt) {
        controleAgenda.add(punt);
    }

    @Override
    public void addWaarschuwingen(List<ControleAgenda> controleAgendas) {
        controleAgenda.addAll(controleAgendas);
    }

    @Override
    public boolean heeftWaarschuwingen() {
        return !controleAgenda.isEmpty();
    }
}
